import 'package:flutter/material.dart';import '../services/api_service.dart';import '../services/realtime_service.dart';import 'order_screen.dart';
class TablesScreen extends StatefulWidget{final VoidCallback onLogout;const TablesScreen({super.key,required this.onLogout});@override State<TablesScreen> createState()=>_TablesScreenState();}class _TablesScreenState extends State<TablesScreen>{List<dynamic> tables=[];bool loading=true;final realtime=RealtimeService();@override void initState(){super.initState();load();realtime.connect(load);}@override void dispose(){realtime.dispose();super.dispose();}Future<void> load()async{try{final value=await ApiService.instance.tables();if(mounted)setState((){tables=value;loading=false;});}catch(_){if(mounted)setState(()=>loading=false);}}Future<void> operate(Map<String,dynamic> table)async{final open=table['status']=='AVAILABLE';if(open){await ApiService.instance.openTable(table['id']);await load();}else{if(!mounted)return;await Navigator.push(context,MaterialPageRoute(builder:(_)=>OrderScreen(table:table)));await load();}}@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Text('Salão principal'),Text(ApiService.instance.user?['name']??'',style:const TextStyle(fontSize:11))]),actions:[IconButton(onPressed:()async{await ApiService.instance.logout();widget.onLogout();},icon:const Icon(Icons.logout))]),body:loading?const Center(child:CircularProgressIndicator()):RefreshIndicator(onRefresh:load,child:GridView.builder(padding:const EdgeInsets.all(16),gridDelegate:const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount:2,crossAxisSpacing:12,mainAxisSpacing:12,childAspectRatio:1.05),itemCount:tables.length,itemBuilder:(_,i){final t=tables[i];final free=t['status']=='AVAILABLE';return Card(child:InkWell(borderRadius:BorderRadius.circular(12),onTap:()=>operate(t),child:Padding(padding:const EdgeInsets.all(16),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('MESA',style:Theme.of(context).textTheme.labelSmall),Text(t['number'],style:Theme.of(context).textTheme.headlineMedium?.copyWith(fontWeight:FontWeight.bold)),const Spacer(),Chip(label:Text(free?'Livre':'Em atendimento'),backgroundColor:free?Colors.grey.shade200:Colors.green.shade100),Text('${t['seats']} lugares',style:Theme.of(context).textTheme.labelSmall)]))));})));}
